module ThreatIntelIndicatorType =
  struct
    type nonrec t =
      | DOMAIN 
      | EMAIL_ADDRESS 
      | HASH_MD5 
      | HASH_SHA1 
      | HASH_SHA256 
      | HASH_SHA512 
      | IPV4_ADDRESS 
      | IPV6_ADDRESS 
      | MUTEX 
      | PROCESS 
      | URL 
      | Non_static_id of string 
    let make i = i
    let to_string =
      function
      | DOMAIN -> "DOMAIN"
      | EMAIL_ADDRESS -> "EMAIL_ADDRESS"
      | HASH_MD5 -> "HASH_MD5"
      | HASH_SHA1 -> "HASH_SHA1"
      | HASH_SHA256 -> "HASH_SHA256"
      | HASH_SHA512 -> "HASH_SHA512"
      | IPV4_ADDRESS -> "IPV4_ADDRESS"
      | IPV6_ADDRESS -> "IPV6_ADDRESS"
      | MUTEX -> "MUTEX"
      | PROCESS -> "PROCESS"
      | URL -> "URL"
      | Non_static_id s -> s
    let of_string =
      function
      | "DOMAIN" -> DOMAIN
      | "EMAIL_ADDRESS" -> EMAIL_ADDRESS
      | "HASH_MD5" -> HASH_MD5
      | "HASH_SHA1" -> HASH_SHA1
      | "HASH_SHA256" -> HASH_SHA256
      | "HASH_SHA512" -> HASH_SHA512
      | "IPV4_ADDRESS" -> IPV4_ADDRESS
      | "IPV6_ADDRESS" -> IPV6_ADDRESS
      | "MUTEX" -> MUTEX
      | "PROCESS" -> PROCESS
