      fun ?criticality ->
        fun ?relatedFindings ->
          fun ?severity ->
            fun ?types ->
              fun () ->
                { confidence; criticality; relatedFindings; severity; types }
    let to_value x =
      structure_to_value
        [("Confidence", (Option.map x.confidence ~f:RatioScale.to_value));
        ("Criticality", (Option.map x.criticality ~f:RatioScale.to_value));
        ("RelatedFindings",
          (Option.map x.relatedFindings ~f:RelatedFindingList.to_value));
        ("Severity",
          (Option.map x.severity ~f:FindingProviderSeverity.to_value));
        ("Types", (Option.map x.types ~f:TypeList.to_value))]
