      let types =
        (Option.map ~f:TypeList.of_xml) (Xml.child xml_arg0 "Types") in
      let severity =
        (Option.map ~f:FindingProviderSeverity.of_xml)
          (Xml.child xml_arg0 "Severity") in
      let relatedFindings =
        (Option.map ~f:RelatedFindingList.of_xml)
          (Xml.child xml_arg0 "RelatedFindings") in
      let criticality =
        (Option.map ~f:RatioScale.of_xml) (Xml.child xml_arg0 "Criticality") in
      let confidence =
        (Option.map ~f:RatioScale.of_xml) (Xml.child xml_arg0 "Confidence") in
      make ?types ?severity ?relatedFindings ?criticality ?confidence ()
