    let of_json json__ =
      let types = field_map json__ "Types" TypeList.of_json in
      let severity =
        field_map json__ "Severity" FindingProviderSeverity.of_json in
      let relatedFindings =
        field_map json__ "RelatedFindings" RelatedFindingList.of_json in
      let criticality = field_map json__ "Criticality" RatioScale.of_json in
      let confidence = field_map json__ "Confidence" RatioScale.of_json in
