      findingProviderFieldsSeverityLabel: StringFilterList.t option
        [@ocaml.doc "The finding provider value for the severity label."];
      findingProviderFieldsSeverityOriginal: StringFilterList.t option
        [@ocaml.doc
          "The finding provider's original value for the severity."];
      findingProviderFieldsTypes: StringFilterList.t option
        [@ocaml.doc
          "One or more finding types that the finding provider assigned to the finding. Uses the format of namespace/category/classifier that classify a finding. Valid namespace values are: Software and Configuration Checks | TTPs | Effects | Unusual Behaviors | Sensitive Data Identifications"];
      sample: BooleanFilterList.t option
        [@ocaml.doc
          "Indicates whether or not sample findings are included in the filter results."];
      complianceSecurityControlId: StringFilterList.t option
        [@ocaml.doc
          "The unique identifier of a control across standards. Values for this field typically consist of an Amazon Web Services service and a number, such as APIGateway.5."];
      complianceAssociatedStandardsId: StringFilterList.t option
        [@ocaml.doc
          "The unique identifier of a standard in which a control is enabled. This field consists of the resource portion of the Amazon Resource Name (ARN) returned for a standard in the DescribeStandards API response."];
      vulnerabilitiesExploitAvailable: StringFilterList.t option
        [@ocaml.doc
          "Indicates whether a software vulnerability in your environment has a known exploit. You can filter findings by this field only if you use Security Hub CSPM and Amazon Inspector."];
      vulnerabilitiesFixAvailable: StringFilterList.t option
        [@ocaml.doc
          "Indicates whether a vulnerability is fixed in a newer version of the affected software packages. You can filter findings by this field only if you use Security Hub CSPM and Amazon Inspector."];
