    let to_value x =
      structure_to_value
        [("ProductArn",
           (Option.map x.productArn ~f:StringFilterList.to_value));
        ("AwsAccountId",
          (Option.map x.awsAccountId ~f:StringFilterList.to_value));
        ("Id", (Option.map x.id ~f:StringFilterList.to_value));
