          (Option.map x.severityProduct ~f:NumberFilterList.to_value));
        ("SeverityNormalized",
          (Option.map x.severityNormalized ~f:NumberFilterList.to_value));
        ("SeverityLabel",
          (Option.map x.severityLabel ~f:StringFilterList.to_value));
        ("Confidence",
          (Option.map x.confidence ~f:NumberFilterList.to_value));
